ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?epoch ?genre WHERE {
  ?play a :Play .
  ?play p:title ?title .
  ?play p:epoch ?epoch .
  ?play p:genre ?genre .
  ?play p:author ?author_lk .
  FILTER(REGEX(STR(?author_lk), "^.*Shakespeare.*$", "i"))
} }
  full: { SELECT ?title ?epoch ?society ?genre WHERE {
  ?play a :Play .
  ?play p:title ?title .
  ?play p:epoch ?epoch .
  ?play p:society ?society .
  ?play p:genre ?genre .
  ?play p:author ?author_lk .
  FILTER(REGEX(STR(?author_lk), "^.*Shakespeare.*$", "i"))
} }
  component_2: { SELECT ?title ?society ?genre WHERE {
  ?play a :Play .
  ?play p:title ?title .
  ?play p:society ?society .
  ?play p:genre ?genre .
  ?play p:author ?author_lk .
  FILTER(REGEX(STR(?author_lk), "^.*Shakespeare.*$", "i"))
} }
}
